SELECT DATE_FORMAT(sign_date, '%Y-%m-%d')
FROM sign_in_record
WHERE user_id = #{userId}
  AND DATE_FORMAT(sign_date, '%Y-%m') = #{yearMonth}
ORDER BY sign_date ASC

SELECT COUNT(*)
FROM sign_in_record
WHERE user_id = #{userId}
  AND sign_date = #{signDate}

SELECT COUNT(*)
FROM sign_in_record
WHERE user_id = #{userId}
  AND DATE_FORMAT(sign_date, '%Y-%m') = #{yearMonth}

SELECT COUNT(*)
FROM sign_in_record
WHERE user_id = #{userId}
  AND DATE_FORMAT(sign_date, '%Y-%m') = #{yearMonth}
  AND is_makeup = 1
